951	\section{Čech acyclicity for the structure sheaf on affine basic-open covers}
952	\label{sec:basic_open_acyclicity}
953	
954	Let $X$ be a $k$-scheme, $U \subseteq X$ an affine open, and $s \subseteq \mathcal O_X(U)$ a set generating the unit ideal. Write $\mathfrak U = \{D(f)\}_{f \in s}$ for the basic-open cover. The Čech cochain complex of the structure sheaf with respect to $\mathfrak U$ is
955	\[
956	  C^n(\mathfrak U, \mathcal O_X) \;=\; \prod_{(f_0,\dots,f_n) \in s^{n+1}} \mathcal O_X\bigl(D(f_0) \cap \cdots \cap D(f_n)\bigr),
957	\]
958	with the standard alternating-coface differential.
959	
960	\begin{definition}[Split epi from an injective index map]
961	  \label{def:Scheme_splitEpi_pi_lift_of_injective}
962	  \lean{AlgebraicGeometry.Scheme.splitEpi_pi_lift_of_injective}
963	  Let $\{M_\alpha\}_{\alpha \in A}$ be a family of $k$-modules and $f : B \to A$ an injective function. Then the canonical projection
964	  \[
965	    \prod_{\alpha \in A} M_\alpha \longrightarrow \prod_{\beta \in B} M_{f(\beta)}
966	  \]
967	  admits a section, hence is a split epimorphism in the category of $k$-modules.
968	\end{definition}
969	
970	\begin{proof}
971	
972	  Choose a retraction of $f$ (possible because $B$ injects into $A$), extend families on $B$ to families on $A$ by the chosen values on the complement, and verify the section identity pointwise.
973	\end{proof}
974	
975	\begin{theorem}[From exactness of cochains to vanishing of Čech cohomology]
976	  \label{thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt}
977	  \lean{AlgebraicGeometry.Scheme.cechCohomology_subsingleton_of_cechCochain_exactAt}
978	  Let $\mathcal F$ be a sheaf of $k$-modules on a $k$-scheme $X$, let $\mathfrak U = \{\mathcal U_i\}$ be an open cover, and let $n \ge 1$. If the Čech cochain complex of $\mathcal F$ with respect to $\mathfrak U$ is exact at degree $n$, then the Čech cohomology group $\check H^n(\mathfrak U, \mathcal F)$ is a subsingleton.
979	\end{theorem}
980	
981	\begin{proof}
982	
983	  Exactness at degree $n$ means that the $n$-cocycles equal the $n$-coboundaries, so the quotient $\check H^n$ has at most one element.
984	\end{proof}
985	
986	\begin{theorem}[Čech acyclicity for the structure sheaf]
987	  \label{thm:basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
988	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
989	  \uses{def:Scheme_basicOpenCover, def:Scheme_IsCechAcyclicCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod, thm:Scheme_basicOpenCover_finset_inf_le, thm:Scheme_basicOpenCover_finset_inf_isLocalization, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
990	  The Čech cohomology $\check H^n(\mathfrak U, \mathcal O_X)$ vanishes for every $n \ge 1$.
991	\end{theorem}
992	
993	\begin{proof}
994	  \uses{thm:Scheme_basicOpenCover_finset_inf_isLocalization, def:Scheme_IsCechAcyclicCover, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
995	  The classical proof proceeds in four steps.
996	
997	  \textbf{Step~1: Reduction to per-generator local exactness.} Since $s$ generates the unit ideal, exactness of a map of $\mathcal O_X(U)$-modules is a local property at the cover $\{D(f)\}_{f \in s}$. It suffices to prove exactness after localizing at each generator $f \in s$.
998	
999	  \textbf{Step~2: Identification of the localized complex.} Localizing at $f$ identifies the factor at $(f_0,\dots,f_n)$ with $\mathcal O_X(U)[1/(f f_0 \cdots f_n)]$. Reassembling, the localized Čech complex is naturally isomorphic to the Čech complex of $D(f)$ with respect to the restricted cover $\{D(f) \cap D(f')\}_{f' \in s}$.
1000	
1001	  \textbf{Step~3: Contraction by extra degeneracy.} In the cover of $D(f)$, the member indexed by $f' = f$ is $D(f)$ itself. The augmented Čech complex therefore admits a section: map a family to its component at $f$. This section extends to an extra degeneracy on the augmented simplicial object, exhibiting the augmented Čech complex as contractible. Consequently the complex is exact in all positive degrees.
1002	
1003	  \textbf{Step~4: Globalization.} Each localized differential is exact, so the unlocalized differential is exact by the local-to-global principle for spanning sets. Hence $\check H^n(\mathfrak U, \mathcal O_X) = 0$ for $n \ge 1$.
1004	\end{proof}
1005	
1006	\begin{remark}[Finite-subspanning reduction]
1007	  \label{rem:basic_open_cech_finite_subspanning}
1008	  Although $s$ need not be finite, the unit ideal condition guarantees a finite subset $s_0 \subseteq s$ already generating the unit ideal. The two covers indexed by $s$ and $s_0$ induce the same sieve on $U$, so the refinement map is a quasi-isomorphism. It therefore suffices to prove acyclicity for a finite cover, which makes every cochain factor a finite product.
1009	\end{remark}
1010	
1011	\begin{remark}[Lean implementation]
1012	  The proof uses the local-to-global exactness theorem for spanning sets, the structure-sheaf-section-as-localization theorem for affine basic opens, exactness preservation under localization, and the extra-degeneracy contraction theorem for augmented simplicial objects. Mathlib does not currently host a formalisation of the Koszul complex or of the Čech-to-derived-functor spectral sequence; the proof above bypasses both by working directly with the augmented complex on each basic-open patch.
1013	\end{remark}
1014	
1015	\subsection{Use in the project}
1016	
1017	The chain built in this chapter composes as follows. Čech acyclicity for the structure sheaf on basic-open covers yields the Čech-acyclic hypothesis. The comparison isomorphism between Čech and derived cohomology (a project-local construction, queued for a subsequent iteration) yields the $\HasCechToHModuleIso$ hypothesis. The existence producer of Theorem~\ref{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen} then assembles these into $\HasAffineCechAcyclicCover$, which the producer of Theorem~\ref{thm:Scheme_instIsAffineHModuleVanishing_of_hasAffineCechAcyclicCover} converts into $\IsAffineHModuleVanishing$. Together with the $H^0$ finiteness ladder of Chapter~\ref{chap:Cohomology_StructureSheafModuleK}, this closes Phase~A step~6 and delivers the genus carrier $\Module.\Finite\,k\,H^1(C, \mathcal O_C)$.
